<!--
	Whitespace-sensitive: <pre> content is preserved verbatim, so the tail after the expression
	tag must NOT break even though the line exceeds printWidth. Print width yields to render
	semantics. Both formatters agree.
-->
<pre>
	aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa ~{xxxxxxxxxx} cc
</pre>

<!-- Same for <textarea>, the other whitespace-sensitive element. -->
<textarea>
	aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa ~{xxxxxxxxxx} cc
</textarea>
